+import React, { useEffect, useState } from 'react';
+import './CharacterBubble.css';
+
+type BubbleType = 'speech' | 'thought';
+
+interface CharacterBubbleProps {
+  type: BubbleType;
+  text: string;
+  timeout?: number; // ms to auto-hide
+  onHide?: () => void;
+}
+
+const CharacterBubble: React.FC<CharacterBubbleProps> = ({ type, text, timeout = 4000, onHide }) => {
+  const [visible, setVisible] = useState(true);
+
+  useEffect(() => {
+    if (timeout > 0) {
+      const timer = setTimeout(() => {
+        setVisible(false);
+        if (onHide) onHide();
+      }, timeout);
+      return () => clearTimeout(timer);
+    }
+  }, [timeout, onHide]);
+
+  if (!visible) return null;
+
+  return (
+    <div className={`bubble bubble-${type}`}>
+      <div className="bubble-text pixel-font">{text}</div>
+      <div className={`bubble-tail bubble-tail-${type}`} />
+    </div>
+  );
+};
+
+export default CharacterBubble;
